var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"…따뜻해.","JPN":"……温かい。","ENG":"...It's so warm.","TWN":"…好溫暖喔。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"여긴… 어디지?","JPN":"ここは……どこ？","ENG":"Where... am I?","TWN":"這裡…是哪裡？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"난 마지막에 분명 눈 속에서 의식을 잃고…","JPN":"最後に覚えているのは、雪に埋もれて、気を失って……","ENG":"The last thing I remember is losing consciousness in the snow...","TWN":"我最後的印象是，在雪中昏過去…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아, 드디어 깨어났네.","JPN":"あ、やっと起きたみたいだね。","ENG":"Oh, you're finally awake.","TWN":"喔，你終於醒啦！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"뿔…?","JPN":"ツノ……？","ENG":"A Horn...?","TWN":"有角…？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아직 사태파악이 안되나 보네.","JPN":"状況がまだ飲み込めていないのかな。","ENG":"I guess you're wondering where you are.","TWN":"看來你還搞不清楚狀況。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"너 사흘씩이나 잠만 잔 거 알아? 이대로 영영 잠드는 줄 알았다고.","JPN":"あなたは三日間ずっと眠ってたんだよ。このまま死んじゃうんじゃないかって思った。","ENG":"You slept for three days straight. I thought you were never going to wake up.","TWN":"你已經昏迷三天三夜了，我還以為你會就這樣睡一輩子呢。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"으아아아!!!","JPN":"うわああっ！！","ENG":"UAAAAAH!!!","TWN":"啊啊啊啊！！！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"케헥?!","JPN":"ぐはっ……！","ENG":"Gah?!","TWN":"欸欸欸？！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"왜 다짜고짜 사람을 덮치는 거야?!","JPN":"何でいきなり襲ってくるわけ！？","ENG":"Why are you suddenly attacking me?!","TWN":"你幹嘛突然撲上來？！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"죽어!!!","JPN":"死ね！！！","ENG":"DIE!!!","TWN":"去死！！！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"죽어요! 이 악마!","JPN":"死になさい！　この悪魔！！","ENG":"DIE!! Devil!","TWN":"去死！你這個魔鬼！！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐?","JPN":"はあ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이게 감히 누구더러 악마라는 거…!","JPN":"今誰に向かって悪魔だなん……！","ENG":"Hey, who are you calling a devil...?!","TWN":"你竟敢說我是魔鬼…！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"켁, 숨 쉴 수가…","JPN":"いっ、息が……","ENG":"Kuh...! I can't breathe...","TWN":"唔，不能呼吸…"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이게…! 진짜…!","JPN":"このっ……！　いい加減に……！","ENG":"Why you...! Errgh...!","TWN":"可惡…！欠揍…！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"꺄앗!","JPN":"きゃあっ！","ENG":"Kyaah!","TWN":"啊啊！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"하아 하… 어때?","JPN":"はぁ……はっ……どう？","ENG":"*Huff* *Huff* That'll teach you.","TWN":"嘿嘿…怎麼樣？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"팔 힘은 내가 더 세다고.","JPN":"腕力はあたしの方が強いみたいだね。","ENG":"My arms are stronger than yours.","TWN":"要比腕力我可不會輸你！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"그 뒤틀린 뿔…! 역시 잘못 본 게 아니었어.","JPN":"そのねじれたツノ……！　やっぱり見間違いじゃない。","ENG":"Your twisted horn...! I knew I didn't mistake it.","TWN":"你頭上那對角…！我果然沒看錯！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"내가 잠든 사이에 무슨 짓을 한 건가요?!","JPN":"私が眠っている間にいったい何をしたんですか！？","ENG":"What did you do to me while I was sleeping?!","TWN":"我昏迷的這段時間你對我做了什麼？！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"무슨 짓을 하긴…! 널 구해주고, 간병해줬지!","JPN":"何って……！　あなたを救い出して、看病していたのよ！","ENG":"What did I do...? I saved your life and took care of you!","TWN":"我做了什麼…！我救了你，還照顧你！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"네…?","JPN":"はい……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"수, 수작부리지 마요! 인간을 도와주는 악마가 있을 리 없잖아요!","JPN":"う、嘘はやめてください！　人間を助ける悪魔なんているはずがありません！","ENG":"D-don't play your tricks on me! No devil would ever help a human!","TWN":"別，別想騙我！魔鬼怎麼可能會救人！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"분명 내 영혼을 눈독들이고 데려온 거야! 그렇죠?!","JPN":"私の魂欲しさにここまで連れてきたに違いない！　絶対そうだ！","ENG":"You brought me here to take my soul, didn't you?!","TWN":"你分明是覬覦我的靈魂才把我帶回來的！我沒說錯吧？！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이게 아까부터 누구더러 악마래! 난 사람이라고!","JPN":"さっきから悪魔、悪魔って……！　あたしは人間よ！","ENG":"How dare you keep calling me a devil! I'm a human!","TWN":"從剛剛就一直說我是魔鬼！我是人好嗎！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"사람…?","JPN":"人間……？","ENG":"A human...?","TWN":"你是人…？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"거짓말! 그럼 머리의 뿔은 어떻게 설명할 셈이죠? 장식이라고 둘러댈 셈인가요?","JPN":"嘘だ！　じゃあその頭のツノはどういうことなんですか？　ただの飾りとでも言うつもりなんですか？","ENG":"Liar! Then how do you explain your horn? Are you going to say that it is a fashion accessory?","TWN":"騙人！那你頭上的角要怎麼解釋？該不會想騙我那是裝飾品吧？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그, 그건…","JPN":"そ、それは……","ENG":"W-well...","TWN":"這是，這是…"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"네가 알 거 없잖아!","JPN":"あなたには関係ないでしょ！","ENG":"That's none of your business!","TWN":"關你什麼事！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"거 봐요! 변명 못 하는 걸 보니 역시 악마잖아요!","JPN":"ほら！　何も説明できないところをみるとやっぱり悪魔なんですね！","ENG":"I knew it! Seeing how you can't make up an excuse, you really are a devil!","TWN":"你看吧！你根本無法解釋，你就是魔鬼！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이게 정말…!","JPN":"だからっ……！","ENG":"Oh, come on...!","TWN":"氣死我…！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"흥, 좋아. 내가 악마라고 쳐.","JPN":"ふん、いいわよ。あたしが悪魔だとしよう。","ENG":"Hmph, fine. Let's say that I'm a devil.","TWN":"哼，好！就當我是魔鬼！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그래도 널 눈 속에서 꺼내주고,","JPN":"でも、あなたを雪の中から引っ張り出して、","ENG":"Still, I pulled you out from the snow,","TWN":"但是我把你從雪堆裡拉出來，"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L5_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"사흘 밤낮 죽을 먹여가며 간병까지 해줬으면…!","JPN":"三日三晩、お粥を食べさせたり必死に看病をしてきたあたしに……！","ENG":"and nursed you for three days feeding you porridge...!","TWN":"是我三天三夜不眠不休地照顧你，還為你吃粥…！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"악마님, 감사합니다! 하고 절을 해야지! 무턱대고 목부터 조르는 게 맞는 거야?!","JPN":"お世話になりました、悪魔様！　って言うべきじゃない！　いきなり首を絞めてくるとかどういうこと！？","ENG":"You should be bowing down to thank my generosity! Not strangling my neck!","TWN":"你好歹該說句，魔鬼大人，謝謝你！這樣才對吧？二話不說就掐住人家的脖子，你有沒有禮貌？！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L8_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"앗…?","JPN":"あっ……？","ENG":"Huh...?","TWN":"呃…？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"그 말도 일리는 있군요.","JPN":"確かにそれもそうですね。","ENG":"You do have a point.","TWN":"你這麼說好像也有道理。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"초면에 실례했어요… 이 악마.","JPN":"いきなり初対面の方に失礼いたしました……悪魔め。","ENG":"Excuse me... devil.","TWN":"初次見面失禮了…魔鬼。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"악마라고 부르지 마! 모르가나 <color=#ffd34c>님</color>이라고 불러!","JPN":"悪魔って呼ぶな！　モルガナ<color=#ffd34c>様</color>って呼びなさい！","ENG":"Don't call me a devil! Call me <color=#ffd34c>Miss</color> Morgana!","TWN":"不准叫我魔鬼，叫我莫甘娜<color=#ffd34c>小姐</color>！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"네? 그렇게 이름을 쉽게 알려줘도 괜찮은 건가요?","JPN":"はい？　そんな簡単に名前を明かしちゃって大丈夫なんですか？","ENG":"What? Are you sure you want to tell me your name so easily?","TWN":"蛤？你這麼輕易就告訴我名字沒關係嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"악마에게 이름엔 특별한 의미가 있어서 자기 이름을 쉽게 안 알려준다고 배웠는데…","JPN":"悪魔の名前には特別な意味があって、簡単に自分の名前を明かそうとはしないって学んだのですが……","ENG":"I learned devils don't easily reveal their name because they have special meaning...","TWN":"我聽說名字對於魔鬼有特殊意義，是不能輕易透漏的…"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그러니까 난 악마가 아니라고오!","JPN":"だから、あたしは悪魔じゃないって言ってるでしょ！","ENG":"Like I said, I'M NOT A DEVIL!","TWN":"就說我不是魔鬼！"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"…그렇군요. 여기가 그루터기라는 마을이고, 당신은 이곳의 주민이라는 거죠?","JPN":"……なるほど。ここは切り株という村で、あなたはここの住民なんですね？","ENG":"...I see. So this is a village called the Stump, and you are a resident here?","TWN":"…原來如此，這裡是一個叫作木墩的村莊，而你是這裡的居民對吧？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"동토를 탐색하던 중에 눈에 파묻힌 절 우연히 발견해서 데려온 거고요.","JPN":"凍土の探索中に、雪に埋もれていた私を偶然見つけ、ここに連れてきたと。","ENG":"And while exploring the gelid lands, you coincidentally found me buried in the snow, and brought me here.","TWN":"然後在搜索凍土時，偶然發現被埋在雪裡的我，就把我帶回來。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":" <color=#ffd34c>우연히</color>가 아니야. 눈더미에서 빛이 반짝이는 걸 봤거든.","JPN":" <color=#ffd34c>偶然</color>ではないわ。雪の中から光が漏れていたのよ。","ENG":"It wasn't <color=#ffd34c>coincidental</color>. We saw something glimmering beneath the snow.","TWN":" 不是<color=#ffd34c>偶然</color>，是因為那堆雪在發光。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"거기에 묻혀 있던 게 사람일 줄은 몰랐지만.","JPN":"まさかそこに人が埋もれているなんて、想像していなかったけどね。","ENG":"But I would've never imagined that a person would be buried there.","TWN":"只是我沒想到埋在雪底下的會是人而已。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"네? 빛이라면…","JPN":"え？　光って……","ENG":"Huh? A light...?","TWN":"什麼？光嗎…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"혹시 이 펜듈럼을 말하는 걸까요?","JPN":"この振り子のことでしょうか？","ENG":"Are you talking about this pendulum?","TWN":"你說這個吊墜嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"맞아. 이렇게 생긴 물건이었어.","JPN":"そうね、たぶん。","ENG":"Yeah. It looked something like that.","TWN":"沒錯，長得像這個的東西。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그건 대체 뭐야?","JPN":"いったいそれは何なの？","ENG":"What is it?","TWN":"那到底是什麼？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"이건…","JPN":"これは……","ENG":"This is...","TWN":"這是…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"역병처럼 사악한 것을 감지하면 빛을 내는 도구예요.","JPN":"疫病のような、邪悪なものの存在を発光することで知らせてくれる道具です。","ENG":"a tool that shines when it detects something evil like the plague.","TWN":"這是感應到像瘟疫一樣邪惡的東西時，就會發光的工具。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"눈속에서도 보일 정도로 밝게 빛났다는 건… 제가 역병에 걸렸다는 뜻일 테고요.","JPN":"雪に埋もれていても外に光が届くほど強く光っていたということは……私は疫病にかかっていたということですね。","ENG":"But if you were able to see it shine through the snow... then that would mean that I'm infected with the plague.","TWN":"在雪裡也會發光…就表示我染上瘟疫的意思。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"앗, 맞아. 내가 찾았을 때부터 넌 역병에 걸려있었거든.","JPN":"あ、そうよ。あたしが見つけたとき、あなたは疫病にかかっていたの。","ENG":"Oh, you're right. You had the plague when I first found you.","TWN":"喔，沒錯。我找到你時，你就已經感染瘟疫了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"진단도 없이 그런 걸 맞힐 수 있다니, 신기한 물건이네.","JPN":"それを検知できるなんて、不思議な振り子ね。","ENG":"But being able to guess that correctly without a diagnosis... That's an amazing thing you got there.","TWN":"竟然不需要診斷就可以確認，真是神奇的東西。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"역시… 전 이미 늦은 거로군요.","JPN":"やっぱり……私はもうダメだったんですね。","ENG":"Just as I thought... I'm too late already.","TWN":"果然…我已經沒救了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"그럼 안녕히.","JPN":"では、ありがとうございました。","ENG":"Then, goodbye.","TWN":"那麼，再見了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"앗?","JPN":"えっ？","ENG":"Huh?","TWN":"蛤？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"잠깐! 뭐하는 거야!","JPN":"ちょっと待って！　何をしているの？","ENG":"Wait! What do you think you're doing?!","TWN":"等一下！你在幹什麼！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"날 공격한 것도 모자라서 이번엔 자길 찌르려 해? 제정신이야?!","JPN":"あたしを襲ってきた次は自分を刺そうとするなんて、頭大丈夫なの！？","ENG":"Attacking me wasn't enough, and now you're going to stab yourself? Are you out of your mind?!","TWN":"攻擊我還不夠，現在還想刺死自己？你有什麼毛病？！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"이거 놔주세요!","JPN":"離してください！","ENG":"Let me go!","TWN":"放開我！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"역병에 걸리면 마물이 돼요! 당신까지 위험해질 수도 있다고요!","JPN":"疫病にかかったら魔物と化してしまう！　あなたまで危険にさらしてしまうんです！","ENG":"People with the plague turn into monsters! Which means that you'll be in danger too!","TWN":"染上瘟疫就會變成怪物！連你可能也會有危險！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"역병은 치료했어! 마물로 변할 일은 없다고!","JPN":"疫病はもう治したの！　魔物になんかならないってば！","ENG":"We treated the plague! So, you won't turn into a monster!","TWN":"瘟疫已經治好了！不會變成怪物的！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"네? 치료라고요?","JPN":"え？　治した？","ENG":"What? You treated it?","TWN":"什麼？治好了？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"하지만 동토역병을 치료한다는 건 불가능한 일이지 않나요?","JPN":"ですが、凍土の疫病を治すのは不可能なことだったはずですが。","ENG":"But isn't it impossible to treat the plague of the gelid lands?","TWN":"可是瘟疫不是不治之症嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"흥, 멀린은 가능해.","JPN":"うん、でもマーリンにはそれができるの。","ENG":"Hmph. Not for Merlin.","TWN":"哼，梅林什麼都能治。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"낫는다기 보단 적철을 이용해 증상을 멈추는 쪽에 가깝지만.","JPN":"治すというより赤鉄を使って症状の進行を止めるという方に近いけど。","ENG":"It's not a cure. More like stopping the symptoms using Violarite.","TWN":"但也不能算是治好，比較像是用赤鐵來抑制症狀。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"적철…? 그게 뭐죠?","JPN":"赤鉄……？　それはなんですか？","ENG":"Violarite...? What's that?","TWN":"赤鐵…？那是什麼？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐야? 그것도 몰라?","JPN":"あれ？　それも知らないの？","ENG":"Huh? You don't know about that either?","TWN":"什麼？你連這個都不知道？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"적철은 동토에서 구할 수 있는 보랏빛 광물을 말하는 거야.","JPN":"赤鉄というのは、凍土で手に入る紫色の鉱物のことよ。","ENG":"Violarite is a purple ore that can be found in the gelid lands.","TWN":"赤鐵是可以在凍土上找到的紫色礦石。"},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"멀린은 이걸 이용해서 연명장치라는 걸 만들어 역병 환자를 치료하고 있지.","JPN":"マーリンはそれを使って作り出した延命装置というもので、疫病にかかった患者たちを治療しているの。","ENG":"Merlin uses it to create a life support device that treats plague patients.","TWN":"梅林利用它製造續命裝置，來治療瘟疫患者。"},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"말도 안 돼요. 평범한 사람이 역병을 치료하다니…","JPN":"ありえません。普通の人間が疫病を治しているなんて……","ENG":"I can't believe it. An ordinary person treating the plague...","TWN":"不可能，普通人怎麼能治療瘟疫…"},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"평범한 사람이 아니니까 가능한 거야.","JPN":"普通の人じゃないよ。","ENG":"It's only possible because she's not an ordinary person.","TWN":"就因為她不是普通人，所以才辦得到。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"멀린은 천 년 넘게 살면서 모든 역사와 지식을 머릿속에 간직하고 있거든.","JPN":"マーリンは千年以上も生きていて、あらゆる歴史や知識を手に入れているの。","ENG":"Merlin has lived for over a thousand years, and has all the history and knowledge in her head.","TWN":"梅林已經活超過一千年，腦袋裡裝的都是滿滿的歷史和知識。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"사람이 천 년을 넘게 살았다고요? 어떻게 그런 일이 가능한 거죠?","JPN":"千年以上生きている人間ですって？　どうしてそんなことが可能なんですか？","ENG":"A person living for over a thousand years? How is that even possible?","TWN":"人能活超過一千年？這怎麼可能？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"간단해. 멀린은 예언의 존재니까.","JPN":"それは、マーリンが予言の存在だからよ。","ENG":"It's simple. It's because Merlin is an entity of prophecy.","TWN":"很簡單，因為梅林就是預言中的那一位。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"예언의 존재라고요? 무슨 예언인데요?","JPN":"予言の存在？　それはどんな予言なんですか？","ENG":"An entity of prophecy? What prophecy?","TWN":"預言中的那一位？什麼預言？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":" <color=#ffd34c>반역자에게 죽은 아발론의 옛왕이 훗날 동토에서 다시 태어나 그루터기를 이끌리라.</color>","JPN":" <color=#ffd34c>反逆者に殺されたアバロンの昔の王が近い将来、凍土で生まれ変わり、切り株を導くであろう。</color>","ENG":"<color=#ffd34c>The old king of Avalon, slain by the traitor, will be reborn in the gelid lands and lead the Stump.</color>","TWN":"<color=#ffd34c>遭叛徒殺害的阿瓦隆國王，將來會在凍土重生並帶領木墩。</color>"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"멀린은 바로 그 예언 속 왕이야. 제자들과 함께 최초로 이곳 그루터기에 정착한 사람이지.","JPN":"マーリンはこの予言の中に出てくる王で、弟子たちとともにこの切り株を最初に見つけた人なの。","ENG":"Merlin is the king from that prophecy. She and her disciples were the first to settle in the Stump.","TWN":"梅林就是那個預言中的國王。她和跟從她的人是最早一起在這塊木墩上定居的人。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"역병으로 버려진 땅이 지금처럼 살만해진 건, 전부 멀린 덕분이라고.","JPN":"疫病によって荒れ地と化していたけど、この場所を人が住めるようにしたのはマーリンなのよ。","ENG":"The only reason this plagued and abandoned land is habitable is all thanks to her.","TWN":"這裡原本因為瘟疫而被遺棄，托梅林的福，才能變成像現在這樣適合居住的地方。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"요정의 도움을 받았다고요…?","JPN":"妖精の助けを借りたんですか……？","ENG":"Did she receive help from a fairy...?","TWN":"是受到精靈的幫助嗎…？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"실례가 안된다면, 저도 그 멀린이라는 분을 한번 만나볼 수 있을까요?","JPN":"もしよければ、私も一度そのマーリンという方にお会いすることはできますか？","ENG":"If she won't mind, can I meet this Merlin person?","TWN":"方便的話，我也可以見見那位梅林嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"실례가 돼. 멀린은 연구 때문에 항상 바쁘거든.","JPN":"ダメよ。マーリンは常に研究で忙しいから。","ENG":"I think she will mind. Merlin's always busy with research.","TWN":"不方便，梅林做研究很忙，"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"너 같은 외지인을 만나려고 시간을 내주진 않을걸?","JPN":"あなたのようなよそ者に会うために時間を割くことはないと思うけど。","ENG":"I don't think she'll make time to see an outsider like you.","TWN":"她不會特地抽出時間來見外地人的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"그럴 수가…","JPN":"そんな……","ENG":"No...","TWN":"怎麼會…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"자, 이번엔 내가 물어볼 차례야.","JPN":"さて、今度はあたしからの質問。","ENG":"Now, it's my turn to ask questions.","TWN":"現在換我發問。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"넌 대체 어디서 왔어? 그런 이상한 옷차림은 살면서 한 번도 본 적이 없는데.","JPN":"あなたはどこからやって来たの？　その変な服装、今まで見たことがないから。","ENG":"Where are you from? I've never seen anyone wear strange clothes like that before.","TWN":"你到底是從哪來的？我活到現在從來沒見過這種奇裝異服。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"아, 전 엘리시온에서 왔어요.","JPN":"あ、私はエリシオンの人間です。","ENG":"Oh, I'm from Elysion.","TWN":"喔，我來自艾利森。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"그리고 이건… 이상한 옷이 아니라 추기경님께 직접 수여받은 팔라딘 제복이고요.","JPN":"そして、これは……変な服装ではなく、枢機卿様が直接私に与えてくださった、パラディンの制服です。","ENG":"And this... isn't strange clothing, it's a paladin's uniform that the Cardinal gave me.","TWN":"還有這個…不是奇裝異服。這是樞機主教親自授予的聖騎士制服。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"엘리시온…? 그게 뭐야?","JPN":"エリシオンって……？","ENG":"Elysion...? What's that?","TWN":"艾利森…？那是什麼？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"뭐, 뭔가요? 마치 처음 듣는 듯한 그 반응은?","JPN":"どうしました？　初めて聞いたような反応ですね？","ENG":"W-what? Why are you acting as if it's your first time hearing of the place?","TWN":"什麼？看你的反應，像是第一次聽到似的？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"처음 듣는데.","JPN":"初めて聞いたけど。","ENG":"Because I am hearing for the first time.","TWN":"是第一次沒錯。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"말도 안 돼요! 세상에서 가장 거대한 문명에 대해 들어본 적도 없다고요?","JPN":"そんな！　世界一の巨大文明であるエリシオンを聞いたことがないんですか？","ENG":"No way! You've never heard of the largest civilization in the world?","TWN":"怎麼可能！你竟然沒聽過世界上最偉大的文明？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"몰라. 우리가 사는 곳 밖에서 사람을 만나는 것 자체가 드문 일이니까.","JPN":"うん、知らない。ここにいる人間がよそ者に会うことは皆無に等しいからね。","ENG":"Nope. It's rare to meet new people outside of where I live.","TWN":"沒聽過。我們基本上過著與世隔絕的生活，很少遇到外地人。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"그럴 수가…","JPN":"そんな……","ENG":"Oh...","TWN":"怎麼可能…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아무튼, 네가 아주아주 먼 곳에서 동토를 가로질러 왔다는 건 알겠네.","JPN":"とにかく、あなたが遥か遠いところから凍土を経て、ここにたどり着いたということだけはわかったよ。","ENG":"Anyway, what I do know is that you crossed the gelid lands from a place very far away.","TWN":"總之，你就是從非常遙遠的地方穿越凍土來到這裡的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아무리 자신감이 넘쳐도 그렇지, 제정신이 아니구나? 대체 얼마나 오랫동안 걸은 거야?","JPN":"無謀なことするのね。普通の人間がやることじゃないわ。いったいどれほど長い期間歩いてきたの？","ENG":"But you're crazy for doing that, no matter how confident you are. How long did it take?","TWN":"就算你對你的腿力很有自信，但還是很有毛病吧？你到底走了多久？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"제가 얼마나 온 건진 잘 몰라요. 눈보라 속을 무작정 걷기만 했거든요.","JPN":"どのくらい歩いたかは自分でもよくわかりません。吹雪の中をひたすら歩いていただけなので。","ENG":"I don't know how long it took. I just kept walking through the snowstorm.","TWN":"我也不知道我走了多久，我只是無意識地在風雪中行走。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_CONFUSION"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뒷일을 생각해야지! 집에는 어떻게 돌아갈 셈이야?","JPN":"短絡的で呆れる！　家にはどうやって帰るつもり？","ENG":"You should've thought it out! How are you going to get back home?","TWN":"你也考慮一下後果吧？那你打算怎麼回去？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"상관없어요. 어차피 돌아갈 수도 없는 걸요.","JPN":"考えていません。そもそも帰ることなんかできないので。","ENG":"It doesn’t matter. I can't go back anyway.","TWN":"無所謂，反正也回不去了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"못 돌아가? 왜?","JPN":"帰れないって、どうして？","ENG":"Can't go back? Why not?","TWN":"回不去？為什麼？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"아… 그게…","JPN":"あ……、それは……","ENG":"Oh... Well...","TWN":"呃…因為…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"…쫓겨났어요.","JPN":"……私は追い出されたんです。","ENG":"...I got exiled.","TWN":"…我是被趕出來的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"고향에서 동토로 추방당했다고? 그건 그냥 죽으란 소리나 마찬가지잖아?","JPN":"故郷から凍土に追い出された？　そんなの死刑宣告と同じじゃない！？","ENG":"You were exiled from your hometown to the gelid lands? That's the same as a death sentence!","TWN":"從家鄉被趕到凍土？那不就等於叫你去死？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"대체 얼마나 큰 잘못을 저질렀길래 그렇게 된 거야?","JPN":"いったいどれほどの重罪を犯せば、そんな罰が下るわけ？","ENG":"How big of a mistake did you make to end up like that?","TWN":"你犯了什麼十惡不赦的錯，他們要這樣對你？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"전 잘못한 거 없어요!","JPN":"私は何も悪いことなんかしていません！","ENG":"I didn't do anything wrong!","TWN":"我才沒有犯錯！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"결국… 제가 믿는 분을 실망시키긴 했지만요.","JPN":"ただ……結果的に私が信頼している方を失望させてしまったのです。","ENG":"But I did... disappoint someone I trusted.","TWN":"我只是…讓相信我的人失望了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"흥.","JPN":"ふん。","ENG":"Hmph.","TWN":"哼。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"세상 반대편까지 도망쳐온 죄인이라니. 날 악마로 의심한 것치곤 너도 엄청 수상하네.","JPN":"世界の裏側まで逃げてきた罪人か。あたしを悪魔だと疑っていた割には相当怪しいじゃない。","ENG":"A sinner from the other side of the world. For someone accusing me of being a devil, you're pretty suspicious yourself.","TWN":"結果你竟然是逃到世界另一端的罪人？那你還敢懷疑我是魔鬼，你自己才有鬼吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"의심은 여전히 하고 있어요! 여긴 대체 뭐하는 곳이죠? 엘리시온 바깥의 동토에 생존자가 있다는 얘긴 들어본 적도 없다구요!","JPN":"私だってまだ疑っています！　ここはいったいどんな場所なんですか？　エリシオンの外の凍土に生存者がいるなんて聞いたことがありません！","ENG":"I'm still suspicious about this place! Where am I? I've never heard of people living in the gelid lands outside of Elysion!","TWN":"我還是在懷疑你！這裡到底是什麼地方？我從來沒聽說過艾利森之外的凍土上還有生還者！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"심지어 동토역병을 치료하는 기술이라뇨? 악마의 힘을 빌리지 않고서야 어떻게 그런 일이 가능한지도 모르겠네요!","JPN":"それに、凍土の疫病を治す術を持っているなんて。悪魔の力でも借りていなければ、どうしてそんなことが可能なのか、私には到底理解できません！","ENG":"And you also have the technology to treat the plague? How can that even be possible without borrowing the power of a devil?!","TWN":"甚至還有治療瘟疫的技術？若不是借助魔鬼的能力，怎麼可能辦得到？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그야 가능하지! 멀린은 못 하는 게 없으니까!","JPN":"そんなの簡単よ、マーリンに不可能はないの！","ENG":"Of course, it's possible! Because Merlin can do anything!","TWN":"當然可能！因為梅林是無所不能的！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"그렇다면 그 멀린이란 사람이 악마인 거겠네요! 당신은 그 악마의 숭배자고요!","JPN":"だとしたら、そのマーリンこそ悪魔に違いありませんね！　すると、あなたはその悪魔の崇拝者ということになります！","ENG":"Then that Merlin person must be a devil! And you're her follower!","TWN":"意思就是梅林是魔鬼吧！而你就是魔鬼的信徒！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭣?!","JPN":"はあっ！？","ENG":"What?!","TWN":"什麼？！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"멀린을 악마 취급하지 마! 죽여버린다!","JPN":"マーリンを悪魔呼ばわりいないで！　殺すわよ！","ENG":"Don't call Merlin a devil! I'll kill you for that!","TWN":"不准你說梅林是魔鬼！我會殺了你！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"역시 포섭에 실패하니 본색을 드러내는군요! 살해협박이라니! 전형적인 이교도답네요!","JPN":"やはり丸め込めそうにないと判断したら、すぐに本性を表すんですね！　殺すと脅してくるなんて、典型的な異教徒のやり方です！","ENG":"Just as I thought. Showing your true colors after failing to turn me! And threatening to kill me?! Typical of a pagan!","TWN":"我就知道，沒辦法說服我就露出真面目了吧！竟然還威脅要殺人！根本是典型的異教徒！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"누가 이교도라는 거야! 고향에서 쫓겨난 죄인 주제에!!","JPN":"誰が異教徒ですって！？　故郷から追放された罪人のくせに！","ENG":"Who are you calling a pagan?! You exiled sinner!","TWN":"誰是異教徒？！你自己被人趕出來還敢說！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"누가 이교도겠어요? 그야 악마를 숭배하는 흉측한 뿔이 달린 당신이죠!","JPN":"誰って、醜いツノの生えた悪魔の崇拝者は、あなたしかいないじゃないですか！","ENG":"Who do you think? It can only be a devil worshipper with the ugly horn on her head!","TWN":"誰是異教徒？當然是你這個崇拜魔鬼的醜角人！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"캬아악! 못 참아!","JPN":"くううっ！　もう我慢できないわ！","ENG":"GRAAA! That's it! I've had it with you!","TWN":"可惡！是你逼我的！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"꺄아! 무슨 짓인가요! 주먹으로 야만스럽게!","JPN":"きゃーっ！　何をするんですか！　殴りかかるなんて、野蛮です！","ENG":"KYAAAH! What's the meaning of this?! Throwing fists like a savage!","TWN":"唉唷！你幹嘛！竟然用拳頭這麼野蠻！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_FIGHT"},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"싸우고 싶은 거면 정정당당히 결투하라고요!","JPN":"戦いたいなら、正々堂々と決闘を申し込んできてください！","ENG":"If you want to fight, then formally challenge me to a duel!","TWN":"要打就堂堂正正地打一場！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"시끄러워! 너 같은 죄인을 구해준 건 실수였으니까 다시 눈 속에 파묻혀버려!","JPN":"うるさい！　あなたみたいな罪人を助けたのは間違いだった。もう一度雪に埋もれてしまえ！","ENG":"Shut it! It was a mistake to rescue a sinner like you. So, I'll bury you back in the snow!","TWN":"你閉嘴！救你這個罪人根本是個錯誤！我要把你重新埋進雪裡！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"앗?","JPN":"えっ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"방금 그건… 무슨 소리죠?","JPN":"今のは……なんの音ですか？","ENG":"What was... that sound?","TWN":"剛剛那是什麼聲音？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"마물이 온다는 신호야.","JPN":"魔物が来るという警報よ。","ENG":"It's the signal that monsters are coming.","TWN":"那是怪物出現的訊號。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"사람들이 위험해.","JPN":"みんなが危ない。","ENG":"The villagers are in danger.","TWN":"大家有危險。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"넌 여기 꼼짝 말고 있어. 알겠지?","JPN":"あなたはここでじっとしていてよね、いい？","ENG":"You stay right here, okay?","TWN":"你就乖乖待在這裡，知道嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L27_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"마물…?","JPN":"魔物……？","ENG":"Monsters...?","TWN":"怪物…？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"저도 같이 가요!","JPN":"私も行きます、待ってください！","ENG":"I'll come with!","TWN":"我也一起去！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};